/**
 * Email notification handler — formats and sends email notifications
 * for order lifecycle events.
 *
 * Integrates with the existing notification architecture by subscribing
 * to EventBus events. The NotificationService handles generic notifications;
 * this handler is responsible specifically for email-formatted messages.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  from: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

const STATUS_LABELS: Record<string, string> = {
  pending: 'Pending',
  confirmed: 'Confirmed',
  shipped: 'Shipped',
  delivered: 'Delivered',
  cancelled: 'Cancelled',
};

const DEFAULT_FROM = 'orders@taskflowpro.com';

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: EmailMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register event handlers for email notification triggers.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created — send order confirmation email.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);

    const itemRows = event.order.items
      .map(
        (item) =>
          `${item.name} x${item.quantity} — $${(item.quantity * item.unitPrice).toFixed(2)}`,
      )
      .join('\n');

    const totalFormatted = `$${event.order.total.toFixed(2)}`;

    const textBody = [
      `Hi ${event.user.name},`,
      '',
      `Thank you for your order (${event.order.id}).`,
      '',
      'Items:',
      itemRows,
      '',
      `Total: ${totalFormatted}`,
      '',
      'We will notify you when your order status changes.',
    ].join('\n');

    const htmlBody = [
      `<h1>Order Confirmation</h1>`,
      `<p>Hi ${event.user.name},</p>`,
      `<p>Thank you for your order (<strong>${event.order.id}</strong>).</p>`,
      `<table>`,
      `<tr><th>Item</th><th>Qty</th><th>Price</th></tr>`,
      ...event.order.items.map(
        (item) =>
          `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${(item.quantity * item.unitPrice).toFixed(2)}</td></tr>`,
      ),
      `</table>`,
      `<p><strong>Total: ${totalFormatted}</strong></p>`,
    ].join('\n');

    this.sendEmail({
      to: event.user.email,
      from: DEFAULT_FROM,
      subject: `Order Confirmation — ${event.order.id}`,
      textBody,
      htmlBody,
    });
  }

  /**
   * Handle order status change — send status update email.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update email for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const prevLabel = STATUS_LABELS[event.previousStatus] ?? event.previousStatus;
    const newLabel = STATUS_LABELS[event.newStatus] ?? event.newStatus;

    const textBody = [
      `Your order ${event.order.id} has been updated.`,
      '',
      `Status: ${prevLabel} → ${newLabel}`,
      '',
      this.getStatusMessage(event.newStatus),
    ].join('\n');

    const htmlBody = [
      `<h1>Order Status Update</h1>`,
      `<p>Your order <strong>${event.order.id}</strong> has been updated.</p>`,
      `<p>Status: <em>${prevLabel}</em> → <strong>${newLabel}</strong></p>`,
      `<p>${this.getStatusMessage(event.newStatus)}</p>`,
    ].join('\n');

    this.sendEmail({
      to: event.order.userId,
      from: DEFAULT_FROM,
      subject: `Order ${event.order.id} — ${newLabel}`,
      textBody,
      htmlBody,
    });
  }

  /**
   * Get a human-friendly message for the new status.
   */
  private getStatusMessage(status: string): string {
    switch (status) {
      case 'confirmed':
        return 'Your order has been confirmed and is being prepared.';
      case 'shipped':
        return 'Your order has been shipped and is on its way.';
      case 'delivered':
        return 'Your order has been delivered. Thank you for your purchase!';
      case 'cancelled':
        return 'Your order has been cancelled.';
      default:
        return 'Your order status has been updated.';
    }
  }

  /**
   * Send an email (in-memory for this demo).
   */
  private sendEmail(params: Omit<EmailMessage, 'sentAt'>): void {
    const email: EmailMessage = {
      ...params,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent to ${params.to}: ${params.subject}`);
  }

  /**
   * Get all sent emails.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Get sent emails for a specific recipient.
   */
  getEmailsForRecipient(recipient: string): EmailMessage[] {
    return this.sentEmails.filter((e) => e.to === recipient);
  }

  /**
   * Get the count of sent emails.
   */
  getSentEmailCount(): number {
    return this.sentEmails.length;
  }

  /**
   * Clear all sent emails (useful for testing).
   */
  clearEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { EmailNotificationHandler } from '../../src/notifications/email-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('EmailNotificationHandler', () => {
  let eventBus: EventBus;
  let handler: EmailNotificationHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    handler = new EmailNotificationHandler(eventBus);
  });

  describe('order:created email', () => {
    it('should send confirmation email on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.from).toBe('orders@taskflowpro.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.subject).toContain('order-1');
    });

    it('should include item details in email body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.textBody).toContain('Widget x2');
      expect(email.textBody).toContain('Gadget x1');
      expect(email.textBody).toContain('$45.00');
      expect(email.textBody).toContain('Hi Alice');
    });

    it('should include HTML body with item table', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('<h1>Order Confirmation</h1>');
      expect(email.htmlBody).toContain('<table>');
      expect(email.htmlBody).toContain('Widget');
      expect(email.htmlBody).toContain('$20.00');
    });
  });

  describe('order:status-changed email', () => {
    it('should send status update email on status change', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('user-1');
      expect(emails[0]?.subject).toContain('order-1');
      expect(emails[0]?.subject).toContain('Confirmed');
    });

    it('should include human-friendly status labels in email', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.textBody).toContain('Confirmed');
      expect(email.textBody).toContain('Shipped');
      expect(email.textBody).toContain('on its way');
    });

    it('should handle delivered status with thank you message', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'delivered',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'shipped',
        newStatus: 'delivered',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.textBody).toContain('delivered');
      expect(email.textBody).toContain('Thank you');
    });

    it('should handle cancelled status', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'cancelled',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'cancelled',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.textBody).toContain('cancelled');
    });

    it('should handle multiple status changes', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      expect(handler.getSentEmailCount()).toBe(2);
      const emails = handler.getSentEmails();
      expect(emails[0]?.subject).toContain('Confirmed');
      expect(emails[1]?.subject).toContain('Shipped');
    });
  });

  describe('email management', () => {
    it('should count sent emails', async () => {
      expect(handler.getSentEmailCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      expect(handler.getSentEmailCount()).toBe(1);
    });

    it('should filter emails by recipient', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(handler.getEmailsForRecipient('alice@example.com')).toHaveLength(1);
      expect(handler.getEmailsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear sent emails', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      handler.clearEmails();
      expect(handler.getSentEmailCount()).toBe(0);
    });
  });

  describe('coexistence with NotificationService', () => {
    it('should work alongside NotificationService on same EventBus', async () => {
      const { NotificationService } = await import(
        '../../src/services/notification.service.js'
      );
      const notifService = new NotificationService(eventBus);

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Both handlers should have received the event
      expect(handler.getSentEmailCount()).toBe(1);
      expect(notifService.getNotificationCount()).toBe(1);
    });
  });
});
